(function(){'use strict';const THEME_KEY = 'schedule-theme';const THEME_DARK = 'dark';const THEME_LIGHT = 'light';class ThemeManager{constructor(){this.currentTheme = this.loadTheme();this.init();}init(){this.applyTheme(this.currentTheme);this.setupToggleButton();}loadTheme(){const saved = localStorage.getItem(THEME_KEY);if(saved)return saved;if(window.matchMedia && window.matchMedia('(prefers-color-scheme:dark)').matches){return THEME_DARK;}return THEME_LIGHT;}saveTheme(theme){localStorage.setItem(THEME_KEY,theme);}applyTheme(theme){document.documentElement.setAttribute('data-theme',theme);this.currentTheme = theme;this.updateToggleButton();}toggleTheme(){const newTheme = this.currentTheme === THEME_DARK ? THEME_LIGHT:THEME_DARK;this.applyTheme(newTheme);this.saveTheme(newTheme);}setupToggleButton(){const btn = document.getElementById('themeToggle');if(!btn){console.warn('Theme toggle button not found');return;}btn.addEventListener('click',()=> this.toggleTheme());}updateToggleButton(){const btn = document.getElementById('themeToggle');if(!btn)return;const icon = this.currentTheme === THEME_DARK ? '☀️':'🌙';const text = this.currentTheme === THEME_DARK ? 'Светлая':'Тёмная';btn.innerHTML = `${icon}<span>${text}</span>`;}}if(document.readyState === 'loading'){document.addEventListener('DOMContentLoaded',()=> new ThemeManager());}else{new ThemeManager();}window.ThemeManager = ThemeManager;})();(function(){'use strict';const API_ENDPOINTS ={SCHEDULE:'/api/schedule',STATS:'/api/stats'};class ScheduleManager{constructor(){this.cache = new Map();this.cacheTimeout = 5 * 60 * 1000;}async applyFilters(){const group = document.getElementById('groupFilter')?.value;const dateFrom = document.getElementById('dateFrom')?.value;const dateTo = document.getElementById('dateTo')?.value;const params = new URLSearchParams();if(group && group !== 'all')params.append('group',group);if(dateFrom)params.append('date_from',dateFrom);if(dateTo)params.append('date_to',dateTo);const cacheKey = params.toString();if(this.cache.has(cacheKey)){const cached = this.cache.get(cacheKey);if(Date.now()- cached.timestamp < this.cacheTimeout){this.renderSchedule(cached.data);return;}}try{const url = `${API_ENDPOINTS.SCHEDULE}?${params}`;const response = await fetch(url);if(!response.ok){throw new Error(`HTTP ${response.status}`);}const data = await response.json();this.cache.set(cacheKey,{data:data,timestamp:Date.now()});this.renderSchedule(data);}catch(error){console.error('Error loading schedule:',error);this.showError('Ошибка загрузки расписания');}}renderSchedule(data){const tbody = document.getElementById('scheduleTableBody');if(!tbody){console.error('Schedule table body not found');return;}if(!data || data.length === 0){tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;">Расписание не найдено</td></tr>';return;}const fragment = document.createDocumentFragment();data.forEach(item =>{const row = document.createElement('tr');row.innerHTML = ` <td><span class="date-badge">${this.escapeHtml(item.date)}</span></td> <td>${this.escapeHtml(item.day_name)}</td> <td><span class="time-badge">${this.escapeHtml(item.time)}</span></td> <td><strong>${this.escapeHtml(item.group_name)}</strong></td> <td>${this.escapeHtml(item.subject_name)}</td> <td>${this.escapeHtml(item.teacher_name)}</td> <td>${this.escapeHtml(item.classroom)}</td> `;fragment.appendChild(row);});tbody.innerHTML = '';tbody.appendChild(fragment);}escapeHtml(text){const div = document.createElement('div');div.textContent = text;return div.innerHTML;}showError(message){const tbody = document.getElementById('scheduleTableBody');if(tbody){tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;color:var(--error-color);">${this.escapeHtml(message)}</td></tr>`;}}clearCache(){this.cache.clear();}}window.scheduleManager = new ScheduleManager();window.applyFilters = function(){return window.scheduleManager.applyFilters();};})();(function(){'use strict';const API_ENDPOINTS ={CHAT:'/api/chat'};class ChatManager{constructor(){this.messageHistory = [];this.maxHistory = 50;this.isProcessing = false;this.init();}init(){const input = document.getElementById('chatInput');const sendBtn = document.getElementById('sendButton');if(input){input.addEventListener('keypress',(e)=>{if(e.key === 'Enter' && !e.shiftKey){e.preventDefault();this.sendMessage();}});}if(sendBtn){sendBtn.addEventListener('click',()=> this.sendMessage());}}addMessage(text,type){const messagesDiv = document.getElementById('chatMessages');if(!messagesDiv){console.error('Chat messages container not found');return;}const messageDiv = document.createElement('div');messageDiv.className = `message ${type}`;messageDiv.textContent = text;messagesDiv.appendChild(messageDiv);this.scrollToBottom(messagesDiv);this.messageHistory.push({text,type,timestamp:Date.now()});if(this.messageHistory.length > this.maxHistory){this.messageHistory.shift();}}removeLastMessage(){const messagesDiv = document.getElementById('chatMessages');if(messagesDiv && messagesDiv.lastChild){messagesDiv.removeChild(messagesDiv.lastChild);this.messageHistory.pop();}}scrollToBottom(element){element.scrollTop = element.scrollHeight;}async sendMessage(){if(this.isProcessing)return;const input = document.getElementById('chatInput');const sendButton = document.getElementById('sendButton');if(!input || !sendButton)return;const message = input.value.trim();if(!message)return;this.addMessage(message,'user');input.value = '';this.isProcessing = true;sendButton.disabled = true;this.addMessage('⏳ Обработка запроса...','ai');try{const response = await fetch(API_ENDPOINTS.CHAT,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({message:message})});if(!response.ok){throw new Error(`HTTP ${response.status}`);}const data = await response.json();this.removeLastMessage();if(data.success){if(data.response.regenerated){this.addMessage(data.response.message,'success');setTimeout(()=>{window.location.reload();},2000);}else{const responseText = data.response.message || JSON.stringify(data.response);this.addMessage(responseText,'ai');}}else{const errorText = data.response?.message || 'Ошибка обработки запроса';this.addMessage(errorText,'error');}}catch(error){console.error('Chat error:',error);this.removeLastMessage();this.addMessage('Ошибка соединения с сервером','error');}finally{this.isProcessing = false;sendButton.disabled = false;input.focus();}}sendExampleQuery(text){const input = document.getElementById('chatInput');if(input){input.value = text;this.sendMessage();}}clearHistory(){this.messageHistory = [];const messagesDiv = document.getElementById('chatMessages');if(messagesDiv){messagesDiv.innerHTML = '';}}}window.chatManager = new ChatManager();window.sendMessage = function(){return window.chatManager.sendMessage();};window.sendExampleQuery = function(element){const query = element.textContent;return window.chatManager.sendExampleQuery(query);};})();(function(){'use strict';const API_ENDPOINTS ={LOGOUT:'/api/logout',REGENERATE_WEEK:'/api/regenerate-week',DELETE_SCHEDULE:'/api/delete-schedule'};class DashboardActions{async logout(){try{await fetch(API_ENDPOINTS.LOGOUT,{method:'POST'});window.location.href = '/';}catch(error){console.error('Logout error:',error);window.location.href = '/';}}async generateSchedule(){const weekSelector = document.getElementById('weekSelector');if(!weekSelector){console.error('Week selector not found');return;}const weekStart = weekSelector.value;if(!weekStart){this.showAlert('Выберите неделю для генерации');return;}if(!confirm(`Сгенерировать расписание на неделю с ${weekStart}?`)){return;}this.showLoading('Генерация расписания...');try{const response = await fetch(API_ENDPOINTS.REGENERATE_WEEK,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({week_start_date:weekStart})});const data = await response.json();this.hideLoading();if(data.success){this.showAlert(data.message,'success');setTimeout(()=> window.location.reload(),1500);}else{this.showAlert('Ошибка:' + data.message,'error');}}catch(error){console.error('Generate error:',error);this.hideLoading();this.showAlert('Ошибка соединения с сервером','error');}}async deleteSchedule(){if(!confirm('Вы уверены,что хотите удалить ВСЁ расписание? Это действие необратимо!')){return;}if(!confirm('Последнее предупреждение! Удалить всё расписание?')){return;}this.showLoading('Удаление расписания...');try{const response = await fetch(API_ENDPOINTS.DELETE_SCHEDULE,{method:'DELETE'});const data = await response.json();this.hideLoading();if(data.success){this.showAlert(data.message,'success');setTimeout(()=> window.location.reload(),1500);}else{this.showAlert('Ошибка:' + data.message,'error');}}catch(error){console.error('Delete error:',error);this.hideLoading();this.showAlert('Ошибка соединения с сервером','error');}}showAlert(message,type = 'info'){alert(message);}showLoading(message){const overlay = document.createElement('div');overlay.id = 'loadingOverlay';overlay.style.cssText = ` position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;z-index:9999;`;const content = document.createElement('div');content.style.cssText = ` background:white;padding:30px;border-radius:10px;text-align:center;color:#333;`;content.innerHTML = ` <div class="spinner"></div> <p style="margin-top:15px;font-size:1.1em;">${message}</p> `;overlay.appendChild(content);document.body.appendChild(overlay);}hideLoading(){const overlay = document.getElementById('loadingOverlay');if(overlay){overlay.remove();}}}window.dashboardActions = new DashboardActions();window.logout = function(){return window.dashboardActions.logout();};window.generateSchedule = function(){return window.dashboardActions.generateSchedule();};window.deleteSchedule = function(){return window.dashboardActions.deleteSchedule();};})();(function(){'use strict';const API_ENDPOINTS ={LOGIN:'/api/login'};class LoginManager{constructor(){this.init();}init(){const form = document.getElementById('loginForm');if(form){form.addEventListener('submit',(e)=> this.handleLogin(e));}const usernameInput = document.getElementById('username');if(usernameInput){usernameInput.focus();}}async handleLogin(event){event.preventDefault();const username = document.getElementById('username')?.value;const password = document.getElementById('password')?.value;const errorMessage = document.getElementById('errorMessage');if(!username || !password){this.showError('Заполните все поля');return;}if(errorMessage){errorMessage.classList.remove('show');}const submitBtn = event.target.querySelector('button[type="submit"]');if(submitBtn){submitBtn.disabled = true;submitBtn.textContent = 'Вход...';}try{const response = await fetch(API_ENDPOINTS.LOGIN,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username,password})});const data = await response.json();if(response.ok && data.success){window.location.href = '/dashboard';}else{this.showError(data.message || 'Ошибка входа');if(submitBtn){submitBtn.disabled = false;submitBtn.textContent = 'Войти';}}}catch(error){console.error('Login error:',error);this.showError('Ошибка соединения с сервером');if(submitBtn){submitBtn.disabled = false;submitBtn.textContent = 'Войти';}}}showError(message){const errorMessage = document.getElementById('errorMessage');if(errorMessage){errorMessage.textContent = message;errorMessage.classList.add('show');setTimeout(()=>{errorMessage.classList.remove('show');},5000);}}}if(document.readyState === 'loading'){document.addEventListener('DOMContentLoaded',()=> new LoginManager());}else{new LoginManager();}})();